from kafka import KafkaProducer
from flask import Flask, request

app = Flask(__name__)

# Securely configure the Kafka producer with necessary credentials and settings
producer = KafkaProducer(bootstrap_servers='your_kafka_broker',
                         security_protocol='SSL',
                         ssl_cafile='path_to_ca_cert',
                         ssl_certfile='path_to_client_cert',
                         ssl_keyfile='path_to_client_key')

ALLOWED_TOPICS = {'topic1', 'topic2', 'topic3'}  # Explicit allowlist of topics

@app.route('/publish', methods=['POST'])
def publish_message():
    topic_name = request.args.get('topic')
    message = request.json.get('message')

    if not topic_name or not message:
        return "Missing topic or message", 400

    if topic_name not in ALLOWED_TOPICS:
        return f"Topic {topic_name} is not allowed", 403

    try:
        producer.send(topic_name, value=message.encode('utf-8'))
        producer.flush()
        return f"Message published to {topic_name}", 200
    except Exception as e:
        return str(e), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)